Code.Terraform:
```hcl
resource "aws_backup_report_plan" "<example_resource_name>" {
  name = "<example_resource_name>" # 重要：少なくとも1つのレポート計画を作成

  report_delivery_channel {
    s3_bucket_name = "<example_resource_name>" # 重要：レポートの宛先バケット
    formats        = ["CSV"] # 重要：有効なレポートファイル形式
  }

  report_setting {
    report_template = "BACKUP_JOB_REPORT" # 重要：最小ジョブレポートテンプレート
  }
}
```
